-- create "members" table
CREATE TABLE "members" ("id" bigint NOT NULL GENERATED BY DEFAULT AS IDENTITY, "created_at" timestamptz NOT NULL, "updated_at" timestamptz NOT NULL, "email" character varying(150) NULL, "phone" character varying(50) NULL, "password_hash" character varying(255) NULL, "status" smallint NOT NULL DEFAULT 1, "meta" jsonb NOT NULL, PRIMARY KEY ("id"), CONSTRAINT "members_status_check" CHECK (status = ANY (ARRAY[0, 1])));
-- create index "members_email_key" to table: "members"
CREATE UNIQUE INDEX "members_email_key" ON "members" ("email");
-- create index "members_phone_key" to table: "members"
CREATE UNIQUE INDEX "members_phone_key" ON "members" ("phone");
-- create "themes" table
CREATE TABLE "themes" ("id" bigint NOT NULL GENERATED BY DEFAULT AS IDENTITY, "created_at" timestamptz NOT NULL, "updated_at" timestamptz NOT NULL, "code" character varying(50) NOT NULL, "name" character varying(100) NOT NULL, "layout_key" character varying(255) NOT NULL, "config_schema" jsonb NOT NULL, "is_active" boolean NOT NULL DEFAULT true, PRIMARY KEY ("id"));
-- create index "themes_code_key" to table: "themes"
CREATE UNIQUE INDEX "themes_code_key" ON "themes" ("code");
-- create "shops" table
CREATE TABLE "shops" ("id" bigint NOT NULL GENERATED BY DEFAULT AS IDENTITY, "created_at" timestamptz NOT NULL, "updated_at" timestamptz NOT NULL, "name" character varying(100) NOT NULL, "status" smallint NOT NULL DEFAULT 1, "content_json" jsonb NOT NULL, "meta" jsonb NOT NULL, "theme_id" bigint NULL, PRIMARY KEY ("id"), CONSTRAINT "shops_themes_theme" FOREIGN KEY ("theme_id") REFERENCES "themes" ("id") ON UPDATE NO ACTION ON DELETE SET NULL, CONSTRAINT "shops_status_check" CHECK (status = ANY (ARRAY[0, 1, 2])));
-- create index "shop_theme_id" to table: "shops"
CREATE INDEX "shop_theme_id" ON "shops" ("theme_id");
-- create "member_refresh_tokens" table
CREATE TABLE "member_refresh_tokens" ("id" bigint NOT NULL GENERATED BY DEFAULT AS IDENTITY, "token_hash" character varying(255) NOT NULL, "expires_at" timestamptz NOT NULL, "revoked_at" timestamptz NULL, "rotated_from" bigint NULL, "created_at" timestamptz NOT NULL, "member_id" bigint NOT NULL, "shop_id" bigint NOT NULL, PRIMARY KEY ("id"), CONSTRAINT "member_refresh_tokens_members_member" FOREIGN KEY ("member_id") REFERENCES "members" ("id") ON UPDATE NO ACTION ON DELETE NO ACTION, CONSTRAINT "member_refresh_tokens_shops_shop" FOREIGN KEY ("shop_id") REFERENCES "shops" ("id") ON UPDATE NO ACTION ON DELETE NO ACTION);
-- create index "member_refresh_tokens_token_hash_key" to table: "member_refresh_tokens"
CREATE UNIQUE INDEX "member_refresh_tokens_token_hash_key" ON "member_refresh_tokens" ("token_hash");
-- create index "memberrefreshtoken_member_id" to table: "member_refresh_tokens"
CREATE INDEX "memberrefreshtoken_member_id" ON "member_refresh_tokens" ("member_id");
-- create index "memberrefreshtoken_shop_id" to table: "member_refresh_tokens"
CREATE INDEX "memberrefreshtoken_shop_id" ON "member_refresh_tokens" ("shop_id");
-- create "pages" table
CREATE TABLE "pages" ("id" bigint NOT NULL GENERATED BY DEFAULT AS IDENTITY, "created_at" timestamptz NOT NULL, "updated_at" timestamptz NOT NULL, "type_key" character varying(50) NOT NULL, "title" character varying(150) NOT NULL DEFAULT '', "slug" character varying(150) NOT NULL, "status" smallint NOT NULL DEFAULT 0, "content_json" jsonb NOT NULL, "published_json" jsonb NULL, "meta" jsonb NOT NULL, "shop_id" bigint NOT NULL, PRIMARY KEY ("id"), CONSTRAINT "pages_shops_pages" FOREIGN KEY ("shop_id") REFERENCES "shops" ("id") ON UPDATE NO ACTION ON DELETE NO ACTION, CONSTRAINT "pages_status_check" CHECK (status = ANY (ARRAY[0, 1])));
-- create index "page_shop_id_slug" to table: "pages"
CREATE UNIQUE INDEX "page_shop_id_slug" ON "pages" ("shop_id", "slug");
-- create index "page_shop_id_status" to table: "pages"
CREATE INDEX "page_shop_id_status" ON "pages" ("shop_id", "status");
-- create "permissions" table
CREATE TABLE "permissions" ("id" bigint NOT NULL GENERATED BY DEFAULT AS IDENTITY, "name" character varying(100) NOT NULL, "description" character varying(255) NOT NULL DEFAULT '', PRIMARY KEY ("id"));
-- create index "permissions_name_key" to table: "permissions"
CREATE UNIQUE INDEX "permissions_name_key" ON "permissions" ("name");
-- create "roles" table
CREATE TABLE "roles" ("id" bigint NOT NULL GENERATED BY DEFAULT AS IDENTITY, "created_at" timestamptz NOT NULL, "updated_at" timestamptz NOT NULL, "name" character varying(50) NOT NULL, "scope" character varying(20) NOT NULL, PRIMARY KEY ("id"), CONSTRAINT "roles_scope_check" CHECK ((scope)::text = ANY ((ARRAY['platform'::character varying, 'merchant'::character varying])::text[])));
-- create index "role_name_scope" to table: "roles"
CREATE UNIQUE INDEX "role_name_scope" ON "roles" ("name", "scope");
-- create "role_permission" table
CREATE TABLE "role_permission" ("role_id" bigint NOT NULL, "permission_id" bigint NOT NULL, PRIMARY KEY ("role_id", "permission_id"), CONSTRAINT "role_permission_permissions_permission" FOREIGN KEY ("permission_id") REFERENCES "permissions" ("id") ON UPDATE NO ACTION ON DELETE NO ACTION, CONSTRAINT "role_permission_roles_role" FOREIGN KEY ("role_id") REFERENCES "roles" ("id") ON UPDATE NO ACTION ON DELETE NO ACTION);
-- create "users" table
CREATE TABLE "users" ("id" bigint NOT NULL GENERATED BY DEFAULT AS IDENTITY, "created_at" timestamptz NOT NULL, "updated_at" timestamptz NOT NULL, "email" character varying(150) NOT NULL, "password_hash" character varying(255) NOT NULL, "status" smallint NOT NULL DEFAULT 1, "meta" jsonb NOT NULL, PRIMARY KEY ("id"), CONSTRAINT "users_status_check" CHECK (status = ANY (ARRAY[0, 1])));
-- create index "users_email_key" to table: "users"
CREATE UNIQUE INDEX "users_email_key" ON "users" ("email");
-- create "role_user" table
CREATE TABLE "role_user" ("id" bigint NOT NULL GENERATED BY DEFAULT AS IDENTITY, "user_id" bigint NOT NULL, "role_id" bigint NOT NULL, "shop_id" bigint NULL, PRIMARY KEY ("id"), CONSTRAINT "role_user_roles_role" FOREIGN KEY ("role_id") REFERENCES "roles" ("id") ON UPDATE NO ACTION ON DELETE NO ACTION, CONSTRAINT "role_user_shops_shop" FOREIGN KEY ("shop_id") REFERENCES "shops" ("id") ON UPDATE NO ACTION ON DELETE CASCADE, CONSTRAINT "role_user_users_user" FOREIGN KEY ("user_id") REFERENCES "users" ("id") ON UPDATE NO ACTION ON DELETE NO ACTION);
-- create index "roleuser_role_id" to table: "role_user"
CREATE INDEX "roleuser_role_id" ON "role_user" ("role_id");
-- create index "roleuser_user_id_shop_id" to table: "role_user"
CREATE INDEX "roleuser_user_id_shop_id" ON "role_user" ("user_id", "shop_id");
-- create "shop_member" table
CREATE TABLE "shop_member" ("id" bigint NOT NULL GENERATED BY DEFAULT AS IDENTITY, "created_at" timestamptz NOT NULL, "updated_at" timestamptz NOT NULL, "points" integer NOT NULL DEFAULT 0, "level_id" integer NULL, "shop_id" bigint NOT NULL, "member_id" bigint NOT NULL, PRIMARY KEY ("id"), CONSTRAINT "shop_member_members_member" FOREIGN KEY ("member_id") REFERENCES "members" ("id") ON UPDATE NO ACTION ON DELETE NO ACTION, CONSTRAINT "shop_member_shops_shop" FOREIGN KEY ("shop_id") REFERENCES "shops" ("id") ON UPDATE NO ACTION ON DELETE NO ACTION);
-- create index "shopmember_member_id" to table: "shop_member"
CREATE INDEX "shopmember_member_id" ON "shop_member" ("member_id");
-- create index "shopmember_shop_id_member_id" to table: "shop_member"
CREATE UNIQUE INDEX "shopmember_shop_id_member_id" ON "shop_member" ("shop_id", "member_id");
-- create "shop_user" table
CREATE TABLE "shop_user" ("id" bigint NOT NULL GENERATED BY DEFAULT AS IDENTITY, "created_at" timestamptz NOT NULL, "shop_id" bigint NOT NULL, "user_id" bigint NOT NULL, PRIMARY KEY ("id"), CONSTRAINT "shop_user_shops_shop" FOREIGN KEY ("shop_id") REFERENCES "shops" ("id") ON UPDATE NO ACTION ON DELETE NO ACTION, CONSTRAINT "shop_user_users_user" FOREIGN KEY ("user_id") REFERENCES "users" ("id") ON UPDATE NO ACTION ON DELETE NO ACTION);
-- create index "shopuser_shop_id_user_id" to table: "shop_user"
CREATE UNIQUE INDEX "shopuser_shop_id_user_id" ON "shop_user" ("shop_id", "user_id");
-- create index "shopuser_user_id" to table: "shop_user"
CREATE INDEX "shopuser_user_id" ON "shop_user" ("user_id");
-- create "sites" table
CREATE TABLE "sites" ("id" bigint NOT NULL GENERATED BY DEFAULT AS IDENTITY, "created_at" timestamptz NOT NULL, "updated_at" timestamptz NOT NULL, "domain" character varying(255) NOT NULL, "ssl_status" smallint NOT NULL DEFAULT 0, "meta" jsonb NOT NULL, PRIMARY KEY ("id"), CONSTRAINT "sites_ssl_status_check" CHECK (ssl_status = ANY (ARRAY[0, 1, 2])));
-- create index "sites_domain_key" to table: "sites"
CREATE UNIQUE INDEX "sites_domain_key" ON "sites" ("domain");
-- create "site_shop" table
CREATE TABLE "site_shop" ("path_prefix" character varying(100) NULL, "is_primary" boolean NOT NULL DEFAULT false, "created_at" timestamptz NOT NULL, "site_id" bigint NOT NULL, "shop_id" bigint NOT NULL, PRIMARY KEY ("site_id", "shop_id"), CONSTRAINT "site_shop_shops_shop" FOREIGN KEY ("shop_id") REFERENCES "shops" ("id") ON UPDATE NO ACTION ON DELETE NO ACTION, CONSTRAINT "site_shop_sites_site" FOREIGN KEY ("site_id") REFERENCES "sites" ("id") ON UPDATE NO ACTION ON DELETE NO ACTION);
-- create index "site_shop_default_shop_per_site" to table: "site_shop"
CREATE UNIQUE INDEX "site_shop_default_shop_per_site" ON "site_shop" ("site_id") WHERE (path_prefix IS NULL);
-- create index "site_shop_primary_domain_per_shop" to table: "site_shop"
CREATE UNIQUE INDEX "site_shop_primary_domain_per_shop" ON "site_shop" ("shop_id") WHERE is_primary;
-- create index "siteshop_site_id_path_prefix" to table: "site_shop"
CREATE UNIQUE INDEX "siteshop_site_id_path_prefix" ON "site_shop" ("site_id", "path_prefix");
-- create "theme_pages" table
CREATE TABLE "theme_pages" ("id" bigint NOT NULL GENERATED BY DEFAULT AS IDENTITY, "created_at" timestamptz NOT NULL, "updated_at" timestamptz NOT NULL, "type_key" character varying(50) NOT NULL, "component_key" character varying(255) NOT NULL, "page_schema" jsonb NOT NULL, "theme_id" bigint NOT NULL, PRIMARY KEY ("id"), CONSTRAINT "theme_pages_themes_pages" FOREIGN KEY ("theme_id") REFERENCES "themes" ("id") ON UPDATE NO ACTION ON DELETE NO ACTION);
-- create index "themepage_theme_id_type_key" to table: "theme_pages"
CREATE UNIQUE INDEX "themepage_theme_id_type_key" ON "theme_pages" ("theme_id", "type_key");
-- create "user_permission" table
CREATE TABLE "user_permission" ("id" bigint NOT NULL GENERATED BY DEFAULT AS IDENTITY, "is_granted" boolean NOT NULL, "user_id" bigint NOT NULL, "permission_id" bigint NOT NULL, "shop_id" bigint NULL, PRIMARY KEY ("id"), CONSTRAINT "user_permission_permissions_permission" FOREIGN KEY ("permission_id") REFERENCES "permissions" ("id") ON UPDATE NO ACTION ON DELETE NO ACTION, CONSTRAINT "user_permission_shops_shop" FOREIGN KEY ("shop_id") REFERENCES "shops" ("id") ON UPDATE NO ACTION ON DELETE CASCADE, CONSTRAINT "user_permission_users_user" FOREIGN KEY ("user_id") REFERENCES "users" ("id") ON UPDATE NO ACTION ON DELETE NO ACTION);
-- create index "userpermission_user_id_shop_id" to table: "user_permission"
CREATE INDEX "userpermission_user_id_shop_id" ON "user_permission" ("user_id", "shop_id");
-- create "user_refresh_tokens" table
CREATE TABLE "user_refresh_tokens" ("id" bigint NOT NULL GENERATED BY DEFAULT AS IDENTITY, "token_hash" character varying(255) NOT NULL, "expires_at" timestamptz NOT NULL, "revoked_at" timestamptz NULL, "rotated_from" bigint NULL, "created_at" timestamptz NOT NULL, "user_id" bigint NOT NULL, PRIMARY KEY ("id"), CONSTRAINT "user_refresh_tokens_users_user" FOREIGN KEY ("user_id") REFERENCES "users" ("id") ON UPDATE NO ACTION ON DELETE NO ACTION);
-- create index "user_refresh_tokens_token_hash_key" to table: "user_refresh_tokens"
CREATE UNIQUE INDEX "user_refresh_tokens_token_hash_key" ON "user_refresh_tokens" ("token_hash");
-- create index "userrefreshtoken_user_id" to table: "user_refresh_tokens"
CREATE INDEX "userrefreshtoken_user_id" ON "user_refresh_tokens" ("user_id");
